// === dma_ring.h — 应用层可见的 ADT 接口 ===
typedef struct dma_ring_buf dma_ring_buf_t;

// 创建环形缓冲区，buf 由调用者分配，size 必须是 2 的幂
dma_ring_buf_t* dma_ring_create(uint8_t* buf, uint32_t size);

// 销毁
void dma_ring_destroy(dma_ring_buf_t* ring);

// 返回可读取字节数（线程安全：读 volatile head/tail）
uint32_t dma_ring_data_available(dma_ring_buf_t* ring);

// 返回可写入字节数
uint32_t dma_ring_write_space(dma_ring_buf_t* ring);

// 读取数据，最多读取 max_len 字节，返回实际读取数
uint32_t dma_ring_read(dma_ring_buf_t* ring, uint8_t* dst, uint32_t max_len);

// ISR 调用：DMA 传输完成后更新 head
void dma_ring_update_head(dma_ring_buf_t* ring, uint16_t new_head);

// === dma_ring.c ===
#include "dma_ring.h"

struct dma_ring_buf {
    uint8_t*    base;      // 缓冲区起始地址
    uint32_t    size;      // 缓冲区大小（2 的幂）
    uint32_t    mask;      // size - 1，用于位运算取模
    volatile uint16_t head; // DMA 写入位置（ISR 更新）
    volatile uint16_t tail; // 应用消费位置
};

static inline uint16_t wrap_idx(dma_ring_buf_t* r, uint16_t idx) {
    return idx & r->mask;  // 位运算替代 % size
}

uint32_t dma_ring_data_available(dma_ring_buf_t* ring) {
    uint16_t h = ring->head;  // volatile read
    uint16_t t = ring->tail;  // volatile read
    if (h >= t) return h - t;
    return (uint16_t)(ring->size - t + h);
}

/**
 * USART1 RX DMA + 环形缓冲区驱动（STM32F4xx, HAL）
 * 缓冲区大小 512 字节，2 的幂，位于 DTCM/RAM2 避免 cache 一致性问题
 */
#define RING_SIZE       512u
#define RING_MASK       (RING_SIZE - 1u)

static uint8_t rx_buf[RING_SIZE] __attribute__((aligned(4)));
static volatile uint16_t rx_head = 0;
static volatile uint16_t rx_tail = 0;

/* DMA 传输完成回调：由 HAL 在中断上下文中调用 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        /* 步骤 1：读取 DMA CNDTR 得到剩余传输字节数 */
        uint32_t remaining = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);

        /* 步骤 2：计算 DMA 已写入的字节数 = SIZE - remaining */
        uint16_t transferred = (uint16_t)(RING_SIZE - remaining);

        /* 步骤 3：总线同步屏障，确保 DMA 写入对核心可见 */
        __DSB();

        /* 步骤 4：更新 head（ISR 写，应用层读，必须 volatile）*/
        rx_head = transferred;

        /* 步骤 5：通知应用层有新数据可用 */
        app_data_ready();  /* 由应用层实现，可能触发任务唤醒 */
    }
}

/* 读取可用数据量：应用层调用 */
uint16_t uart_ring_available(void) {
    uint16_t h = rx_head;  /* volatile read */
    uint16_t t = rx_tail;  /* volatile read */
    if (h >= t) return h - t;
    return RING_SIZE - t + h;
}

/* 从环形缓冲区读取数据，返回实际读取字节数 */
uint16_t uart_ring_read(uint8_t* dst, uint16_t max_len) {
    uint16_t avail = uart_ring_available();
    if (avail == 0) return 0;

    uint16_t len = (max_len < avail) ? max_len : avail;
    uint16_t tail = rx_tail;

    /* 分两段复制：尾部连续段 + 头部环绕段 */
    uint16_t first_chunk = (RING_SIZE - tail) & RING_MASK;
    if (first_chunk == 0) first_chunk = RING_SIZE;

    uint16_t copy1 = (len < first_chunk) ? len : first_chunk;
    for (uint16_t i = 0; i < copy1; i++) {
        dst[i] = rx_buf[(tail + i) & RING_MASK];
    }

    if (len > copy1) {
        for (uint16_t i = 0; i < len - copy1; i++) {
            dst[copy1 + i] = rx_buf[i];
        }
    }

    rx_tail = (uint16_t)((tail + len) & RING_MASK);
    return len;
}

/**
 * 安全读取环形缓冲区：避免 head/tail 竞态的死锁陷阱
 * 使用快照模式读取 head 和 tail
 */
static inline uint16_t uart_ring_read_safe(uint8_t* dst, uint16_t max_len) {
    /* 步骤 1：快照 head 和 tail，避免在循环中被 ISR 修改 */
    uint16_t head_snapshot = rx_head;  /* volatile read, 原子 */
    uint16_t tail_snapshot = rx_tail;  /* volatile read, 原子 */

    /* 步骤 2：基于快照计算可用数据量 */
    uint16_t avail;
    if (head_snapshot >= tail_snapshot) {
        avail = head_snapshot - tail_snapshot;
    } else {
        avail = RING_SIZE - tail_snapshot + head_snapshot;
    }

    if (avail == 0) return 0;

    /* 步骤 3：限制读取长度 */
    uint16_t len = (max_len < avail) ? max_len : avail;

    /* 步骤 4：执行实际读取（基于快照，不会被 ISR 干扰）*/
    uint16_t tail = tail_snapshot;
    for (uint16_t i = 0; i < len; i++) {
        dst[i] = rx_buf[tail & RING_MASK];
        tail = (tail + 1) & RING_MASK;
    }

    /* 步骤 5：原子更新 tail（关闭中断保护）*/
    __disable_irq();
    rx_tail = tail;
    __enable_irq();

    return len;
}

/**
 * 溢出检测：在 ISR 中调用
 */
volatile bool dma_buffer_overflow = false;

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        uint32_t remaining = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);
        uint16_t transferred = (uint16_t)(RING_SIZE - remaining);

        /* 检测：如果 transferred 比上次记录的 head 减少了超过 RING_SIZE/2，
         * 说明缓冲区被写满了，发生了溢出 */
        static uint16_t prev_head = 0;
        if ((transferred - prev_head) & RING_MASK > RING_SIZE / 2) {
            dma_buffer_overflow = true;  /* 应用层应定期检查此标志 */
        }

        __DSB();
        rx_head = transferred;
        prev_head = transferred;
        app_data_ready();
    }
}

// ============================================
// 【重构前】裸 DMA 搬运代码 — 大泥球反模式
// ============================================
/* 原始代码的问题：
 * 1. 缓冲区大小 256 硬编码在三个地方
 * 2. ISR 中直接操作裸指针 rx_ptr
 * 3. app_process_data() 可能在 ISR 中阻塞
 * 4. 没有环形逻辑，溢出时静默丢数据
 * 5. head/tail 没有 volatile，编译器可能优化掉
 */

static uint8_t rx_data[256];
static uint8_t* rx_ptr = rx_data;
static uint8_t* rx_start = rx_data;

void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        uint32_t rem = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);
        uint16_t count = 256 - rem;  /* 硬编码 256 */

        /* 直接处理数据 — 可能在 ISR 中阻塞！*/
        app_process_data(rx_ptr, count);

        /* 重置指针 — 没有环形逻辑，溢出即丢数据 */
        rx_ptr = rx_data;
    }
}

// ============================================
// 【重构后】结构化环形缓冲区 ADT
// ============================================
/* 改进点：
 * 1. 缓冲区大小通过宏定义，一处修改全局生效
 * 2. head/tail 用 volatile 保护，编译器不优化
 * 3. ISR 只做 head 更新和标志设置，数据消费放任务层
 * 4. 环形逻辑正确处理 head 环绕
 * 5. 溢出检测 + Cache 一致性支持
 */

#define UART_RX_RING_SIZE   512u
#define UART_RX_RING_MASK   (UART_RX_RING_SIZE - 1u)

static uint8_t uart_rx_buf[UART_RX_RING_SIZE] __attribute__((aligned(8)));
static volatile uint16_t uart_rx_head = 0;
static volatile uint16_t uart_rx_tail = 0;
static volatile bool uart_rx_overflow = false;

/* ISR 中调用：仅更新 head，不做数据消费 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == USART1) {
        uint32_t rem = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);
        uint16_t transferred = (uint16_t)(UART_RX_RING_SIZE - rem);

        /* 溢出检测：如果 transferred 回绕超过一半，说明缓冲区满了 */
        uint16_t prev_head = uart_rx_head;
        if ((transferred - prev_head) & UART_RX_RING_MASK > UART_RX_RING_SIZE / 2) {
            uart_rx_overflow = true;
        }

        __DSB();  /* 确保 DMA 写入对核心可见 */
        uart_rx_head = transferred;

        /* 唤醒应用层任务（非阻塞）*/
        osSignalSet(uart_rx_task_handle, 0x01);
    }
}

/* 应用层任务中调用：消费数据 */
void uart_rx_task(void const* argument) {
    for (;;) {
        osEventFlagsWait(0x01, osFlagsWaitAny, osWaitForever);

        /* 读取可用数据量（快照模式避免竞态）*/
        uint16_t head = uart_rx_head;
        uint16_t tail = uart_rx_tail;
        uint16_t avail = (head >= tail) ? (head - tail) : 
                                  (UART_RX_RING_SIZE - tail + head);

        if (avail > 0) {
            /* 分段复制：尾部段 + 头部环绕段 */
            uint16_t first = (UART_RX_RING_SIZE - tail) & UART_RX_RING_MASK;
            if (first == 0) first = UART_RX_RING_SIZE;
            uint16_t copy1 = (avail < first) ? avail : first;

            /* 这里可以做 Cache Clean，如果是 M7 核 */
            #if defined(__CORTEX_M) && (__CORTEX_M == 7)
            SCB_CleanDCache_by_Addr(
                (void*)&uart_rx_buf[tail & UART_RX_RING_MASK],
                copy1, 8);
            #endif

            /* 消费数据（在任务上下文中，可以阻塞）*/
            app_process_data(&uart_rx_buf[tail & UART_RX_RING_MASK], copy1);

            /* 更新 tail */
            uart_rx_tail = (uint16_t)((tail + copy1) & UART_RX_RING_MASK);
        }

        /* 清除溢出标志 */
        if (uart_rx_overflow) {
            uart_rx_overflow = false;
            log_warning("UART RX buffer overflow detected");
        }
    }
}
